import { NextRequest, NextResponse } from "next/server";
import { predictStockFuture } from "@/lib/stockPredictor";

interface CacheEntry {
  data: any;
  timestamp: number;
  symbol: string;
  horizon: number;
}

const cache = new Map<string, CacheEntry>();
const CACHE_DURATION_MS = 5 * 60 * 1000; // 5 minutes

function getCacheKey(symbol: string, horizon: number, asOfDate?: string): string {
  return `${symbol}-${horizon}-${asOfDate || 'current'}`;
}

function isCacheValid(entry: CacheEntry): boolean {
  return Date.now() - entry.timestamp < CACHE_DURATION_MS;
}

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const symbol = searchParams.get("symbol")?.trim().toUpperCase();
    const horizon = parseInt(searchParams.get("horizon") || "7");
    const asOfDate = searchParams.get("asOfDate") || undefined;

    if (!symbol) {
      return NextResponse.json({ error: "Symbol is required" }, { status: 400 });
    }

    const cacheKey = getCacheKey(symbol, horizon, asOfDate);
    const cachedEntry = cache.get(cacheKey);

    if (cachedEntry && isCacheValid(cachedEntry)) {
      console.log(`Cache hit for ${cacheKey}`);
      return NextResponse.json(cachedEntry.data, {
        headers: { "Cache-Control": "no-store" },
      });
    }

    console.log(`Cache miss for ${cacheKey}, fetching from API`);
    
    // Forward to the actual predict API
    const predictUrl = new URL(`${request.url}/../predict`);
    predictUrl.searchParams.set("symbol", symbol);
    predictUrl.searchParams.set("horizon", horizon.toString());
    if (asOfDate) {
      predictUrl.searchParams.set("asOfDate", asOfDate);
    }

    const response = await fetch(predictUrl.toString());
    const data = await response.json();

    if (!response.ok) {
      return NextResponse.json(data, { status: response.status });
    }

    // Cache the successful response
    cache.set(cacheKey, {
      data,
      timestamp: Date.now(),
      symbol,
      horizon,
    });

    // Clean old cache entries periodically
    if (cache.size > 50) {
      for (const [key, entry] of cache.entries()) {
        if (!isCacheValid(entry)) {
          cache.delete(key);
        }
      }
    }

    return NextResponse.json(data, {
      headers: { "Cache-Control": "no-store" },
    });
  } catch (error) {
    console.error("Cached predict API error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}
